"""## Time Scaled Popularity

### Formula
![CIS520.png](data:image/png;base64,)


### Key Points
- Song Age and Popularity values are provided in the dataset.
- Popularity decays exponentially over time.
  - Decay between days **10–20** is greater than decay between days **100–120**.
- Different music is popular at different times → this metric helps capture that shift.

"""

import numpy as np
from datetime import datetime

def add_time_features(df):
    df["track_album_release_date"] = pd.to_datetime(
        df["track_album_release_date"], errors="coerce"
    )

    today = datetime.today()
    df["song_age_days"] = (today - df["track_album_release_date"]).dt.days
    df["release_year"] = df["track_album_release_date"].dt.year
    df["release_decade"] = (df["release_year"] // 10) * 10

    # time-scaled popularity
    df["time_scaled_popularity"] = df["track_popularity"] / (
        1 + np.log1p(df["song_age_days"])
    )

    return df

df = add_time_features(df)

