"""# Feature Selection and Target Definition

"""

def get_correlated_features(dataframe, threshold=0.85):
    corr_matrix = dataframe.corr().abs()

    # Upper triangle mask
    upper = corr_matrix.where(
        np.triu(np.ones(corr_matrix.shape), k=1).astype(bool)
    )

    # Features to drop
    to_drop = [
        column for column in upper.columns
        if any(upper[column] > threshold)
    ]

    return to_drop

redundant_features = get_correlated_features(numeric_df, threshold=0.85)

print("Highly correlated features to REMOVE:")
print(redundant_features)

df_pruned = df.drop(columns=['release_year', 'release_decade'])
print("New shape after pruning:", df_pruned.shape)

irrelevant_categorical = [
    'track_href', 'uri', 'track_album_name','playlist_name', 'analysis_url', 'track_id', 'track_name','track_album_id', 'id', 'type',
    'playlist_id'
]

df_pruned = df_pruned.drop(columns=[col for col in irrelevant_categorical if col in df_pruned.columns])
print("New shape after pruning:", df_pruned.shape)
df_pruned = df_pruned.dropna(subset=["track_popularity", "time_scaled_popularity"])
print("After dropping NaN targets:", df_pruned.shape)

all_cols = df_pruned.columns.tolist()
final_features = [
    c for c in all_cols
    if c not in ["track_popularity", "time_scaled_popularity"]
]

X = df_pruned[final_features]

# Target 1: raw popularity
y_raw = df_pruned["track_popularity"]

# Target 2: time-scaled popularity
y_scaled = df_pruned["time_scaled_popularity"]

print("Number of predictors:", len(final_features))
print("Predictors:", final_features)

# preprocessing (scaling + one hot)
numeric_features = X.select_dtypes(include=['float64', 'int64']).columns.tolist()
categorical_features = X.select_dtypes(include=['object']).columns.tolist()

print("\nNumeric features:", numeric_features)
print("Categorical features:", categorical_features)

from sklearn.preprocessing import StandardScaler, OneHotEncoder
from sklearn.compose import ColumnTransformer
from sklearn.impute import SimpleImputer
from sklearn.pipeline import Pipeline

preprocessor = ColumnTransformer(
    transformers=[
        ("num", Pipeline([
            ("imputer", SimpleImputer(strategy="median")),
            ("scaler", StandardScaler())
        ]), numeric_features),

        ("cat", Pipeline([
            ("imputer", SimpleImputer(strategy="most_frequent")),
            ("onehot", OneHotEncoder(handle_unknown="ignore"))
        ]), categorical_features)
    ]
)

from sklearn.model_selection import KFold, cross_val_score
from sklearn.metrics import make_scorer, mean_absolute_error, mean_squared_error, r2_score
import numpy as np

mae = make_scorer(mean_absolute_error, greater_is_better=False)
rmse = make_scorer(lambda y, y_pred: np.sqrt(mean_squared_error(y, y_pred)),
                   greater_is_better=False)
r2 = make_scorer(r2_score)

def run_cross_validation(model, X, y, folds=5):
    cv = KFold(n_splits=folds, shuffle=True, random_state=42)
    scores = {}

    mae_scores = cross_val_score(model, X, y, cv=cv, scoring=mae)
    scores["MAE_mean"] = -mae_scores.mean()
    scores["MAE_std"] = mae_scores.std()

    rmse_scores = cross_val_score(model, X, y, cv=cv, scoring=rmse)
    scores["RMSE_mean"] = -rmse_scores.mean()
    scores["RMSE_std"] = rmse_scores.std()

    r2_scores = cross_val_score(model, X, y, cv=cv, scoring=r2)
    scores["R2_mean"] = r2_scores.mean()
    scores["R2_std"] = r2_scores.std()

    return scores

"""# Models"""

from sklearn.pipeline import Pipeline
from sklearn.linear_model import LinearRegression

model = Pipeline([
    ("prep", preprocessor),
    ("reg", LinearRegression())
])

print("\n=== Predicting RAW Popularity (track_popularity) ===")
raw_results = run_cross_validation(model, X, y_raw)
print(raw_results)

print("\n=== Predicting TIME-SCALED Popularity (time_scaled_popularity) ===")
scaled_results = run_cross_validation(model, X, y_scaled)
print(scaled_results)

"""Findings related to previous cell - Linear regression explains ~53% of the pattern in popularity, Removing the age effect (time scaling) did NOT dramatically change predictability, MAE probably lower for time-scaled because the scale is smaller"""

# ---------------------------------------------------------
# LINEAR REGRESSION WITH TRAIN/TEST SPLIT
# ---------------------------------------------------------

from sklearn.model_selection import train_test_split
from sklearn.pipeline import Pipeline
from sklearn.linear_model import LinearRegression
from sklearn.metrics import mean_absolute_error, mean_squared_error, r2_score
import numpy as np

# ------------------------
# 1. Prepare data
# ------------------------

X = df_pruned[final_features]
y_raw = df_pruned["track_popularity"]
y_scaled = df_pruned["time_scaled_popularity"]

# Use the SAME train/test split for both targets
X_train, X_test, y_raw_train, y_raw_test = train_test_split(
    X, y_raw, test_size=0.2, random_state=42
)

_, _, y_scaled_train, y_scaled_test = train_test_split(
    X, y_scaled, test_size=0.2, random_state=42
)

# ------------------------
# 2. Build Linear Regression pipeline
#     (includes imputer + scaler + one-hot)
# ------------------------

linreg_model = Pipeline([
    ("prep", preprocessor),   # from your earlier pipeline (imputer + scaler + ohe)
    ("lr", LinearRegression())
])

# ------------------------
# 3. Fit + Predict for RAW Popularity
# ------------------------

linreg_model.fit(X_train, y_raw_train)
raw_preds = linreg_model.predict(X_test)

raw_mae = mean_absolute_error(y_raw_test, raw_preds)
raw_rmse = np.sqrt(mean_squared_error(y_raw_test, raw_preds))
raw_r2 = r2_score(y_raw_test, raw_preds)

print("\n=== Linear Regression — RAW Popularity (track_popularity) ===")
print("MAE :", raw_mae)
print("RMSE:", raw_rmse)
print("R²  :", raw_r2)

# ------------------------
# 4. Fit + Predict for TIME-SCALED Popularity
# ------------------------

linreg_model.fit(X_train, y_scaled_train)
scaled_preds = linreg_model.predict(X_test)

scaled_mae = mean_absolute_error(y_scaled_test, scaled_preds)
scaled_rmse = np.sqrt(mean_squared_error(y_scaled_test, scaled_preds))
scaled_r2 = r2_score(y_scaled_test, scaled_preds)

print("\n=== Linear Regression — TIME-SCALED Popularity ===")
print("MAE :", scaled_mae)
print("RMSE:", scaled_rmse)
print("R²  :", scaled_r2)

